import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, RadarChart, Radar, PolarGrid, PolarAngleAxis } from 'recharts';
import { predictYield } from '../context/api';

const crops = ['Rice', 'Wheat', 'Maize', 'Tomato', 'Cotton', 'Sugarcane', 'Soybean'];

const defaults = { crop: 'Rice', rainfall: 850, temperature: 28, soil_n: 120, soil_p: 60, soil_k: 80, ph: 6.5, fertilizer: 200, area: 2 };

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload?.length) return (
    <div style={{ background: '#1E293B', border: '1px solid #334155', borderRadius: '8px', padding: '10px 14px', fontSize: '12px' }}>
      <div style={{ color: '#94A3B8', marginBottom: '4px' }}>{label}</div>
      {payload.map((p, i) => <div key={i} style={{ color: p.color, fontWeight: 700 }}>{p.name}: {p.value} t/ha</div>)}
    </div>
  );
  return null;
};

export default function YieldPrediction() {
  const [form, setForm] = useState(defaults);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const update = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const submit = async () => {
    setLoading(true); setError(''); setResult(null);
    try {
      const res = await predictYield(form);
      setResult(res.data);
    } catch {
      setError('Backend not reachable. Run: cd backend && python app.py');
    }
    setLoading(false);
  };

  const radarData = result ? Object.entries(result.feature_importance).map(([k, v]) => ({ subject: k, value: v })) : [];

  return (
    <div className="fade-in">
      <div className="page-header">
        <div>
          <div className="page-title">📊 Yield Prediction</div>
          <div className="page-sub">ML-powered crop yield forecasting using ensemble models</div>
        </div>
        <span className="tag tag-cyan">Random Forest + Gradient Boosting · R²=0.91</span>
      </div>

      {error && <div style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.3)', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#EF4444', fontSize: '13px' }}>⚠️ {error}</div>}

      <div className="card mb-20">
        <div className="section-title">⚙️ Input Parameters</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '16px', marginBottom: '20px' }}>
          <div>
            <label>Crop Type</label>
            <select className="select" value={form.crop} onChange={e => update('crop', e.target.value)}>
              {crops.map(c => <option key={c}>{c}</option>)}
            </select>
          </div>
          {[
            { key: 'rainfall', label: 'Rainfall (mm)', placeholder: 'e.g. 850', min: 0, max: 3000 },
            { key: 'temperature', label: 'Temperature (°C)', placeholder: 'e.g. 28', min: 10, max: 45 },
            { key: 'soil_n', label: 'Soil Nitrogen (kg/ha)', placeholder: 'e.g. 120', min: 0, max: 300 },
            { key: 'soil_p', label: 'Soil Phosphorus (kg/ha)', placeholder: 'e.g. 60', min: 0, max: 150 },
            { key: 'soil_k', label: 'Soil Potassium (kg/ha)', placeholder: 'e.g. 80', min: 0, max: 200 },
            { key: 'ph', label: 'Soil pH', placeholder: 'e.g. 6.5', min: 4, max: 9, step: 0.1 },
            { key: 'fertilizer', label: 'Fertilizer Used (kg)', placeholder: 'e.g. 200', min: 0, max: 500 },
            { key: 'area', label: 'Field Area (hectare)', placeholder: 'e.g. 2', min: 0.1, max: 100, step: 0.1 },
          ].map(f => (
            <div key={f.key}>
              <label>{f.label}</label>
              <input type="number" className="input" value={form[f.key]} placeholder={f.placeholder}
                min={f.min} max={f.max} step={f.step || 1}
                onChange={e => update(f.key, parseFloat(e.target.value) || 0)} />
            </div>
          ))}
        </div>
        <button className="btn btn-cyan" onClick={submit} disabled={loading}>
          {loading ? <><span className="spinner" /> Predicting...</> : '📊 Predict Yield'}
        </button>
      </div>

      {result && (
        <div className="fade-in">
          <div className="grid-3 mb-20">
            <div className="card card-accent-cyan" style={{ textAlign: 'center', padding: '28px' }}>
              <div style={{ fontSize: '13px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '10px' }}>Yield Per Hectare</div>
              <div style={{ fontSize: '52px', fontWeight: 900, color: '#22D3EE', letterSpacing: '-2px', lineHeight: 1 }}>{result.predicted_yield_per_ha}</div>
              <div style={{ color: '#94A3B8', marginTop: '6px' }}>tons / hectare</div>
              <div style={{ marginTop: '14px', padding: '8px 14px', background: result.vs_district_pct >= 0 ? 'rgba(74,222,128,0.12)' : 'rgba(239,68,68,0.12)', border: `1px solid ${result.vs_district_pct >= 0 ? 'rgba(74,222,128,0.3)' : 'rgba(239,68,68,0.3)'}`, borderRadius: '8px' }}>
                <span style={{ color: result.vs_district_pct >= 0 ? '#4ADE80' : '#EF4444', fontWeight: 700, fontSize: '13px' }}>
                  {result.vs_district_pct >= 0 ? '↑' : '↓'} {Math.abs(result.vs_district_pct)}% vs district avg ({result.district_average} t/ha)
                </span>
              </div>
            </div>

            <div className="card card-accent-green" style={{ textAlign: 'center', padding: '28px' }}>
              <div style={{ fontSize: '13px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '10px' }}>Total Production</div>
              <div style={{ fontSize: '52px', fontWeight: 900, color: '#4ADE80', letterSpacing: '-2px', lineHeight: 1 }}>{result.total_yield}</div>
              <div style={{ color: '#94A3B8', marginTop: '6px' }}>total tons ({result.area} ha)</div>
              <div style={{ marginTop: '14px', color: 'var(--text-muted)', fontSize: '13px' }}>
                Est. Revenue: <span style={{ color: '#4ADE80', fontWeight: 700 }}>₹{(result.total_yield * 18000).toLocaleString()}</span>
              </div>
            </div>

            <div className="card" style={{ padding: '28px' }}>
              <div className="section-title">🤖 Model Details</div>
              {[
                ['Algorithm', 'Random Forest + GBM'],
                ['R² Score', '0.91'],
                ['MAE', '0.18 t/ha'],
                ['Training Data', '28,000 records'],
                ['Features Used', '7 key factors'],
              ].map(([k, v]) => (
                <div key={k} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', fontSize: '12px', borderBottom: '1px solid var(--border)' }}>
                  <span style={{ color: 'var(--text-muted)' }}>{k}</span>
                  <span style={{ color: '#CBD5E1', fontWeight: 600 }}>{v}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="grid-2">
            <div className="card">
              <div className="section-title">📉 Monthly Yield Trend</div>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={result.monthly_trend}>
                  <CartesianGrid stroke="#1E293B" strokeDasharray="4 4" vertical={false} />
                  <XAxis dataKey="month" tick={{ fill: '#64748B', fontSize: 12 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: '#64748B', fontSize: 11 }} axisLine={false} tickLine={false} />
                  <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(255,255,255,0.03)' }} />
                  <Bar dataKey="yield" name="Yield" fill="#22D3EE" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="card">
              <div className="section-title">🎯 Feature Importance</div>
              {Object.entries(result.feature_importance).map(([k, v]) => (
                <div key={k} style={{ marginBottom: '10px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                    <span style={{ fontSize: '13px', color: '#CBD5E1' }}>{k}</span>
                    <span style={{ fontSize: '12px', color: '#22D3EE', fontWeight: 700 }}>{v}%</span>
                  </div>
                  <div className="progress-bar" style={{ height: '7px' }}>
                    <div className="progress-fill" style={{ width: `${v}%`, background: `linear-gradient(90deg, #22D3EE60, #22D3EE)` }} />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
